const result = $input.first().json;

if (!result || result.valid !== true) {
  throw new Error('Invalid request signature');
}

return [{ json: { hmac_valid: true } }];

const session = $input.first().json;

if (!session || !session.user_id) {
  throw new Error('Invalid or expired token');
}

const body = $('Receive Session Request').first().json.body;
const canViewAll = ['owner', 'admin'].includes(session.role);

const target_user_id = (canViewAll && body.target_user_id)
  ? body.target_user_id
  : session.user_id;

return [{
  json: {
    user_id: session.user_id,
    target_user_id,
    role: session.role,
    client_id: session.client_id,
    slug: session.slug,
  }
}];

const points = $input.first().json.result.points;

if (!points || points.length === 0) {
  return [{ json: { sessions: [] } }];
}

const sessionMap = {};
for (const point of points) {
  const p = point.payload;
  const sid = p.session_id;
  if (!sessionMap[sid]) {
    sessionMap[sid] = { session_id: sid, title: p.question.substring(0, 60), last_message_at: p.timestamp, message_count: 0 };
  }
  sessionMap[sid].message_count++;
  if (p.timestamp > sessionMap[sid].last_message_at) {
    sessionMap[sid].last_message_at = p.timestamp;
    sessionMap[sid].title = p.question.substring(0, 60);
  }
}

const sessions = Object.values(sessionMap).sort((a, b) => b.last_message_at.localeCompare(a.last_message_at));

return [{ json: { sessions } }];
